import { ObjectId } from 'mongodb';

export interface User {
  id: ObjectId;
  username: string;
  passwordHash: string;
  email: string;
  createdAt: Date;
}

export interface UserDTO {
  id: string;
  username: string;
  email: string;
  createdAt: string;
}

import { User } from './user.model';
import { MongoClient, ObjectId } from 'mongodb';

class UserRepository {
  private db;

  constructor(client: MongoClient) {
    this.db = client.db();
  }

  async createUser(user: Omit<User, 'id'>): Promise<User> {
    const result = await this.db.collection<User>('users').insertOne(user);
    return { id: result.insertedId, ...user };
  }

  async findUserByUsername(username: string): Promise<User | null> {
    return this.db.collection<User>('users').findOne({ username });
  }

  async findUserById(id: string): Promise<User | null> {
    return this.db.collection<User>('users').findOne({ id: new ObjectId(id) });
  }
}

export default UserRepository;

import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import UserRepository from '../user/user.repository';
import { UserDTO } from '../user/user.dto';

class AuthService {
  private userRepository: UserRepository;

  constructor(userRepository: UserRepository) {
    this.userRepository = userRepository;
  }

  async register(username: string, password: string, email: string): Promise<UserDTO> {
    const passwordHash = await bcrypt.hash(password, 10);
    const user = await this.userRepository.createUser({ username, passwordHash, email, createdAt: new Date() });
    return { id: user.id.toString(), username: user.username, email: user.email, createdAt: user.createdAt.toISOString() };
  }

  async login(username: string, password: string): Promise<string> {
    const user = await this.userRepository.findUserByUsername(username);
    if (!user || !await bcrypt.compare(password, user.passwordHash)) {
      throw new Error('Invalid credentials');
    }
    return jwt.sign({ userId: user.id }, process.env.JWT_SECRET!, { expiresIn: '1h' });
  }
}

export default AuthService;

import { Request, Response } from 'express';
import AuthService from './auth.service';
import { RegisterInput, LoginInput, validateRegisterInput, validateLoginInput } from './auth.validator';

class AuthController {
  private authService: AuthService;

  constructor(authService: AuthService) {
    this.authService = authService;
  }

  async register(req: Request, res: Response): Promise<void> {
    const input: RegisterInput = req.body;
    try {
      validateRegisterInput(input);
      const user = await this.authService.register(input.username, input.password, input.email);
      res.status(201).json({ success: true, data: user });
    } catch (error) {
      res.status(400).json({ success: false, message: error.message });
    }
  }

  async login(req: Request, res: Response): Promise<void> {
    const input: LoginInput = req.body;
    try {
      validateLoginInput(input);
      const token = await this.authService.login(input.username, input.password);
      res.json({ success: true, data: { token } });
    } catch (error) {
      res.status(401).json({ success: false, message: error.message });
    }
  }
}

export default AuthController;

import { z } from 'zod';

export const RegisterInput = z.object({
  username: z.string().min(3),
  password: z.string().min(6),
  email: z.string().email()
});

export const LoginInput = z.object({
  username: z.string().min(3),
  password: z.string().min(6)
});

export function validateRegisterInput(input: unknown): asserts input is z.infer<typeof RegisterInput> {
  RegisterInput.parse(input);
}

export function validateLoginInput(input: unknown): asserts input is z.infer<typeof LoginInput> {
  LoginInput.parse(input);
}

import { z } from 'zod';

const envSchema = z.object({
  JWT_SECRET: z.string(),
  RATE_LIMIT_MAX: z.string().transform(Number),
  RATE_LIMIT_WINDOW: z.string().transform(Number)
});

envSchema.parse(process.env);

export default envSchema;

import helmet from 'helmet';
import cors from 'cors';
import rateLimit from 'express-rate-limit';

const securityMiddleware = [
  helmet(),
  cors({ origin: ['https://trusted.domain.com'] }),
  rateLimit({
    windowMs: Number(process.env.RATE_LIMIT_WINDOW),
    max: Number(process.env.RATE_LIMIT_MAX)
  })
];

export default securityMiddleware;

import pino from 'pino';

const logger = pino({
  timestamp: pino.stdTimeFunctions.isoTime
});

export default logger;
